import { NextResponse } from 'next/server';
import { supabase } from '@/lib/supabase';
import { getAdminServerSession } from '@/lib/admin-auth';

export const dynamic = 'force-dynamic';
export const revalidate = 0;

// Default settings when no data exists in Supabase
const DEFAULT_SETTINGS = {
    cms_colors: { primary: '#C9A96E', primaryDark: '#B8954F', background: '#FFFFFF', text: '#1C1C1E' },
    cms_hero: { title: 'SELIS HOME CONCEPT', subtitle: 'Premium Mobilya & Ev Dekorasyonu', image: '' },
    cms_footer: { description: 'Evinizin yeni hikayesi.', showNewsletter: true },
    cms_announcement: { enabled: false, text: '', bg: '#C9A96E', color: '#FFFFFF' },
    site_info: {
        siteName: 'SELIS HOME CONCEPT',
        siteSlogan: 'Premium Mobilya & Ev Dekorasyonu',
        siteDescription: 'Evinizin yeni hikayesi.',
        contactEmail: '',
        contactPhone: '',
        supportEmail: '',
        logo: '',
        favicon: '',
        address: { full: '', city: '', district: '' },
    },
    site_social: { instagram: '', facebook: '', whatsapp: '', youtube: '', twitter: '' },
    site_seo: { metaTitle: 'SELIS HOME CONCEPT', metaDescription: '', ogImage: '' },
};

// GET: Site ayarlarini getir (Public)
export async function GET() {
    try {
        const { data, error } = await supabase
            .from('site_settings')
            .select('key, value')
            .order('key');

        if (error) {
            // Table may not exist — return defaults gracefully
            console.warn('site_settings fetch error:', error.message);
            return NextResponse.json(DEFAULT_SETTINGS);
        }

        if (!data || data.length === 0) {
            return NextResponse.json(DEFAULT_SETTINGS);
        }

        // Build settings object from key-value rows
        const settings: Record<string, any> = { ...DEFAULT_SETTINGS };
        for (const row of data) {
            try {
                settings[row.key] = typeof row.value === 'string' ? JSON.parse(row.value) : row.value;
            } catch {
                settings[row.key] = row.value;
            }
        }

        return NextResponse.json(settings);
    } catch (err: any) {
        console.error('Settings GET error:', err);
        return NextResponse.json(DEFAULT_SETTINGS);
    }
}

// POST: Site ayarlarini guncelle (Admin only)
export async function POST(req: Request) {
    try {
        const session = await getAdminServerSession();
        if (!session) {
            return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
        }

        const body = await req.json();

        // Validate: body must be a non-null object with allowed keys
        const ALLOWED_KEYS = ['cms_colors', 'cms_hero', 'cms_footer', 'cms_announcement', 'site_info', 'site_social', 'site_seo'];
        if (!body || typeof body !== 'object' || Array.isArray(body)) {
            return NextResponse.json({ error: 'Invalid request body' }, { status: 400 });
        }
        const invalidKeys = Object.keys(body).filter(k => !ALLOWED_KEYS.includes(k));
        if (invalidKeys.length > 0) {
            return NextResponse.json({ error: `Invalid settings keys: ${invalidKeys.join(', ')}` }, { status: 400 });
        }
        if (Object.keys(body).length === 0) {
            return NextResponse.json({ error: 'No settings provided' }, { status: 400 });
        }

        // Upsert each top-level key as a separate row
        const upserts = Object.entries(body).map(([key, value]) => ({
            key,
            value: typeof value === 'object' ? JSON.stringify(value) : value,
            updated_at: new Date().toISOString(),
        }));

        const { error } = await supabase
            .from('site_settings')
            .upsert(upserts, { onConflict: 'key' });

        if (error) {
            console.warn('site_settings upsert error:', error.message);
            return NextResponse.json({ success: false, message: error.message }, { status: 500 });
        }

        return NextResponse.json({ success: true });
    } catch (err: any) {
        console.error('Settings POST error:', err);
        return NextResponse.json({ error: err.message }, { status: 500 });
    }
}
